const functions = require('@google-cloud/functions-framework');
const sgMail = require('@sendgrid/mail');
const twilio = require('twilio');

function getEnv(name, required = true) {
  const value = process.env[name];
  if (required && (!value || !String(value).trim())) {
    throw new Error(`Missing required environment variable: ${name}`);
  }
  return value;
}

function initSendGrid() {
  const apiKey = getEnv('SENDGRID_API_KEY');
  sgMail.setApiKey(apiKey);
}

function initTwilio() {
  const accountSid = getEnv('TWILIO_ACCOUNT_SID');
  const authToken = getEnv('TWILIO_AUTH_TOKEN');
  const client = twilio(accountSid, authToken);
  const fromNumber = getEnv('TWILIO_FROM_NUMBER');
  return { client, fromNumber };
}

async function sendEmail({ to, from, subject, text, html }) {
  if (!to || !from || !subject || (!text && !html)) {
    throw new Error('Invalid email payload. Required: to, from, subject, and text or html.');
  }

  const msg = {
    to,
    from,
    subject,
    text: text || undefined,
    html: html || undefined,
  };

  const [response] = await sgMail.send(msg);
  return {
    provider: 'sendgrid',
    statusCode: response.statusCode,
    messageId: response.headers && (response.headers['x-message-id'] || response.headers['X-Message-Id']) || null,
  };
}

async function sendSms({ to, body }, twilioClient, fromNumber) {
  if (!to || !body) {
    throw new Error('Invalid SMS payload. Required: to, body.');
  }

  const message = await twilioClient.messages.create({
    to,
    from: fromNumber,
    body,
  });

  return {
    provider: 'twilio',
    sid: message.sid,
    status: message.status,
  };
}

functions.http('notify', async (req, res) => {
  try {
    if (req.method !== 'POST') {
      res.set('Allow', 'POST');
      return res.status(405).json({ error: 'Method not allowed' });
    }

    initSendGrid();
    const { client: twilioClient, fromNumber } = initTwilio();

    const { type, email, sms } = req.body || {};

    if (type === 'email') {
      const result = await sendEmail(email || {});
      return res.status(200).json({ ok: true, result });
    }

    if (type === 'sms') {
      const result = await sendSms(sms || {}, twilioClient, fromNumber);
      return res.status(200).json({ ok: true, result });
    }

    if (type === 'both') {
      const results = {};
      if (email) results.email = await sendEmail(email);
      if (sms) results.sms = await sendSms(sms, twilioClient, fromNumber);
      return res.status(200).json({ ok: true, result: results });
    }

    return res.status(400).json({
      error: 'Invalid request. Expected type to be "email", "sms", or "both".',
    });
  } catch (error) {
    console.error('Notification function error:', error);
    return res.status(500).json({
      ok: false,
      error: error.message || 'Internal server error',
    });
  }
});

module.exports = {
  sendEmail,
  sendSms,
};